export function graphql(source: "\n  query transactions($limit: Int!, $offset: Int!, $startDate: Datetime!, $endDate: Datetime!) {\n    transactions(first: $limit, offset: $offset, orderBy: BLOCK_ID_DESC) {\n      totalCount\n      nodes {\n        id\n        code\n        block {\n          timestamp\n          height\n        }\n        gasUsed\n        gasWanted\n        signerAddress\n        fees\n        messages {\n          nodes {\n            typeUrl\n            json\n          }\n        }\n      }\n    }\n    validTxs: transactions(\n      filter: {\n        code: { equalTo: 0 }\n        block: { timestamp: { greaterThanOrEqualTo: $startDate, lessThanOrEqualTo: $endDate} }\n      }\n    ) {\n      totalCount\n    }\n    failedTxs: transactions(\n      filter: {\n        code: { notEqualTo: 0 }\n        block: { timestamp: { greaterThanOrEqualTo: $startDate, lessThanOrEqualTo: $endDate} }\n      }\n    ) {\n      totalCount\n    }\n    latestBlock: blocks(first: 1, orderBy: HEIGHT_DESC) {\n      nodes {\n        height\n        totalTxs\n      }\n    }\n  }\n"): (typeof documents)["\n  query transactions($limit: Int!, $offset: Int!, $startDate: Datetime!, $endDate: Datetime!) {\n    transactions(first: $limit, offset: $offset, orderBy: BLOCK_ID_DESC) {\n      totalCount\n      nodes {\n        id\n        code\n        block {\n          timestamp\n          height\n        }\n        gasUsed\n        gasWanted\n        signerAddress\n        fees\n        messages {\n          nodes {\n            typeUrl\n            json\n          }\n        }\n      }\n    }\n    validTxs: transactions(\n      filter: {\n        code: { equalTo: 0 }\n        block: { timestamp: { greaterThanOrEqualTo: $startDate, lessThanOrEqualTo: $endDate} }\n      }\n    ) {\n      totalCount\n    }\n    failedTxs: transactions(\n      filter: {\n        code: { notEqualTo: 0 }\n        block: { timestamp: { greaterThanOrEqualTo: $startDate, lessThanOrEqualTo: $endDate} }\n      }\n    ) {\n      totalCount\n    }\n    latestBlock: blocks(first: 1, orderBy: HEIGHT_DESC) {\n      nodes {\n        height\n        totalTxs\n      }\n    }\n  }\n"];

export function graphql(source: string) {
  return (documents as any)[source] ?? {};
}

